import postgres from 'postgres';
const docId = '6491a849-95a2-49cb-b919-b3d95b9d33bc';
const sql = postgres(process.env.PROD_URL, { max: 1, prepare: false, connect_timeout: 30 });
try {
  const settings = await sql`SELECT key, value::text AS raw_value FROM settings WHERE key IN ('require_workflow_map_for_ingestion','default_workflow_read_route','model_pool_workflow_read') ORDER BY key`;
  const doc = await sql`SELECT status, macro_health, left(processing_error, 220) AS processing_error_prefix, processed_at FROM documents WHERE id = ${docId}`;
  const claims = await sql`SELECT count(DISTINCT ce.claim_id)::int AS claim_count FROM claim_evidence ce JOIN document_chunks dc ON dc.id = ce.source_document_chunk_id WHERE dc.document_id = ${docId} AND ce.claim_id IS NOT NULL`;
  const maps = await sql`SELECT status, count(*)::int FROM source_workflow_maps WHERE document_id = ${docId} GROUP BY status ORDER BY status`;
  const latestJobs = await sql`SELECT trigger_run_id, job_type, status, left(error, 180) AS error_prefix, output_json, started_at, finished_at FROM job_runs WHERE input_json->>'documentId' = ${docId} ORDER BY started_at DESC LIMIT 8`;
  console.log(JSON.stringify({ settings, doc, claims, maps, latestJobs }, null, 2));
} finally { await sql.end(); }
